package org.apache.commons.codec.binary.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;

import org.apache.commons.codec.binary.Base64;

public class StepDefs {

    private Base64 base64;
    private byte[] inputBytes;
    private String encodedResult;

    @Given("I have a Base64 instance created with the default constructor")
    public void i_have_a_Base64_instance_created_with_the_default_constructor() {
        base64 = new Base64(); // default constructor, should be unchunked
    }

    @When("I encode a byte array containing {int}")
    public void i_encode_a_byte_array_containing_minus72(int byteValue) {
        try {
            inputBytes = new byte[]{(byte)byteValue};
            encodedResult = base64.encodeToString(inputBytes);
        } catch (Exception e) {
            fail("Exception occurred during encoding: " + e.getMessage());
        }
    }

    @Then("the encoded result should be {string}")
    public void the_encoded_result_should_be(String expected) {
        assertEquals("Encoded result should match expected value", expected, encodedResult);
    }

    @Then("the encoded result should not be {string}")
    public void the_encoded_result_should_not_be(String unexpected) {
        assertNotEquals("Encoded result should not match unexpected value", unexpected, encodedResult);
    }
}

